-- ----------------------------
-- Table structure for sam_achievement
-- ----------------------------
DROP TABLE IF EXISTS `sam_achievement`;
CREATE TABLE `sam_achievement`  (
  `achievement_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `session_id` int UNSIGNED NOT NULL COMMENT '届次 id',
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '类别（字典表 id，政府类/学会类）',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '作品/团队名称',
  `team_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '团队名称',
  `level` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '级别（字典 id）',
  `grade` int NOT NULL COMMENT '获奖等级（字典 id）',
  `track` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '赛道',
  `certificate_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '证书编号（唯一）',
  `group_id` int NULL DEFAULT NULL COMMENT '组别（字典 id）',
  `award_time` date NOT NULL COMMENT '获奖时间',
  `year` int NOT NULL COMMENT '年份',
  `owner_dep_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '部门',
  `is_reimburse` tinyint(1) NOT NULL COMMENT '是否报销',
  `is_supplement` tinyint(1) NULL DEFAULT NULL COMMENT '是否补录',
  `fee` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '报名费金额',
  `reimbursement_fee` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '实际报销金额',
  `reimbursement_ratio` tinyint UNSIGNED NULL DEFAULT NULL COMMENT '报销百分比（0-100）',
  `reimbursement_item_id` int UNSIGNED NULL DEFAULT NULL COMMENT '报销项目 id',
  `reimbursement_date` datetime(0) NULL DEFAULT NULL COMMENT '报销发放时间',
  `item_index` int NULL DEFAULT NULL COMMENT '报销项目序号',
  `quality_index` int NULL DEFAULT NULL COMMENT '素质提升序号',
  `submitted_at` datetime(0) NULL DEFAULT NULL COMMENT '提交时间',
  `reviewed_at` datetime(0) NULL DEFAULT NULL COMMENT '院级审核时间',
  `school_reviewed_at` datetime(0) NULL DEFAULT NULL COMMENT '校级审核时间',
  `review_result` tinyint NOT NULL DEFAULT 0 COMMENT '院级审核结果（待院级审核0，院级驳回1，院级审核通过2）',
  `schooi_review_result` tinyint NOT NULL DEFAULT 0 COMMENT '校级审核结果（待校级审核2，校级审核通过1，校级驳回0 ）',
  `review_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '院级审核不通过原因',
  `school_review_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '校级审核不通过原因',
  `audit_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '院级审核人',
  `school_audit_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '校级审核人',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建者',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新者',
  `create_time` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `update_time` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  `del_flag` tinyint(1) NOT NULL DEFAULT 0 COMMENT '删除标志（0正常 2删除）',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '备注',
  PRIMARY KEY (`achievement_id`) USING BTREE,
  UNIQUE INDEX `uk_certificate_no`(`certificate_no`) USING BTREE,
  INDEX `idx_award_time`(`award_time`) USING BTREE,
  INDEX `idx_grade`(`grade`) USING BTREE,
  INDEX `idx_session`(`session_id`) USING BTREE,
  CONSTRAINT `fk_achievement_session` FOREIGN KEY (`session_id`) REFERENCES `sam_competition_session` (`session_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 24 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '成果主表' ROW_FORMAT = Dynamic;

