-- ----------------------------
-- Table structure for sam_competition_session
-- ----------------------------
DROP TABLE IF EXISTS `sam_competition_session`;
CREATE TABLE `sam_competition_session`  (
  `session_id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `competition_id` bigint NOT NULL COMMENT '赛事ID（关联competition.id）',
  `session` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '届次（例如2025、十九届）',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '类别（政府类/学会类）',
  `organizations` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '盖章单位（多个分号分隔）',
  `level` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '级别（Ⅰ级/Ⅱ级）',
  `tags` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（素质提升表/白名单，多个分号分隔）',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '状态（0=停用，1=启用）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime(0) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标记（0=存在，2=删除）',
  PRIMARY KEY (`session_id`) USING BTREE,
  INDEX `idx_competition_id`(`competition_id`) USING BTREE,
  CONSTRAINT `fk_session_competition_id` FOREIGN KEY (`competition_id`) REFERENCES `sam_competition` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 29 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '届次表' ROW_FORMAT = Dynamic;

